import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
    const [rooms, setRooms] = useState([]);

    useEffect(() => {
        fetchRooms();
    }, []);

    const fetchRooms = async () => {
        const response = await axios.get('/api/rooms');
        setRooms(response.data);
    };

    const addRoom = async (room) => {
        await axios.post('/api/rooms', room);
        fetchRooms();
    };

    const updateRoom = async (id, updatedRoom) => {
        await axios.put(`/api/rooms/${id}`, updatedRoom);
        fetchRooms();
    };

    const deleteRoom = async (id) => {
        await axios.delete(`/api/rooms/${id}`);
        fetchRooms();
    };

    return (
        <div>
            <h1>Room Management System</h1>
            <RoomForm addRoom={addRoom} />
            <RoomList rooms={rooms} updateRoom={updateRoom} deleteRoom={deleteRoom} />
        </div>
    );
