class MasterKeyManager:
    @staticmethod
    def get_master_key():
        return MASTER_KEY

    @staticmethod
    def get_provider(provider_name):
        if provider_name not in PROVIDER_REGISTRY:
            raise ValueError(f"Provider {provider_name} not found")
        provider_path = PROVIDER_REGISTRY[provider_name]
        module_path, class_name = provider_path.rsplit('.', 1)
        module = __import__(module_path, fromlist=[class_name])
        provider_class = getattr(module, class_name)
        return provider_class(MASTER_KEY)

class EncryptionManager:
    @staticmethod
    def encrypt_data(provider_name, data):
        provider = MasterKeyManager.get_provider(provider_name)
        return provider.encrypt(data)

    @staticmethod
    def decrypt_data(provider_name, data):
        provider = MasterKeyManager.get_provider(provider_name)
